import ErrorLog from './components/ErrorLog';
import TradingViewWidget from './components/TradingViewWidget';
import SignalOverlay from './components/SignalOverlay';

const App: React.FC = () => {
  return (
    <EnvironmentProvider>
      <AuthProvider>
        <ThemeProvider>
          <EdgeLightingProvider>
            <HashRouter>
              <AppContextProvider>
                <PageDataProvider>
                  <AppContent />
                </PageDataProvider>
              </AppContextProvider>
            </HashRouter>
          </EdgeLightingProvider>
        </ThemeProvider>
      </AuthProvider>
    </EnvironmentProvider>
  );
};

const AppContent: React.FC = () => {
  const environment = useEnvironment();
  const location = useLocation();
  const { isSeasonalModeActive } = usePageData();
  const isChartingPage = location.pathname === '/charting';

  // Calculate dynamic top spacing
  // Header height logic: 2.5rem (h-10) for charting, 4rem (h-16) for standard
  const headerHeight = isChartingPage ? 2.5 : 4; 
  const navHeight = 3.5; // rem
  const ribbonHeight = 2.5; // rem
  const isDashboard = location.pathname === '/dashboard';

  let topSpacingRem = headerHeight;

  // Add Nav height only if on dashboard page (as nav is hidden elsewhere)
  if (isDashboard) {
      topSpacingRem += navHeight;
  }

  // Add Ribbon height if active
  if (isSeasonalModeActive) {
      topSpacingRem += ribbonHeight;
  }

  const chartTopSpacing = `${topSpacingRem}rem`;

  useEffect(() => {
    const splashScreen = document.getElementById('splash-screen');
    if (splashScreen) {
      splashScreen.style.opacity = '0';
      splashScreen.addEventListener('transitionend', () => splashScreen.remove());
    }
  }, []);

  // Lock body scroll when on charting page to ensure rigid application feel
  useEffect(() => {
    if (isChartingPage) {
      document.body.style.overflow = 'hidden';
      document.body.style.overscrollBehavior = 'none';
    } else {
      document.body.style.overflow = '';
      document.body.style.overscrollBehavior = '';
    }
    return () => {
      document.body.style.overflow = '';
      document.body.style.overscrollBehavior = '';
    };
  }, [isChartingPage]);

  return (
    <ResponsiveFix>
      <div className="relative isolate flex flex-col h-screen text-gray-800 dark:text-gray-200 font-sans overflow-hidden">
        <SeasonalRibbon />
        <Notifications />

        {/* Persistent Chart Container */}
        <div 
          style={{ 
            visibility: isChartingPage ? 'visible' : 'hidden',
            position: 'fixed',
            top: chartTopSpacing, 
            left: 0,
            right: 0,
            bottom: 0,
            zIndex: 30, // Below Header (z-50) and Nav (z-40)
          }}
          className="bg-gray-100 dark:bg-gray-900 flex flex-col pointer-events-auto"
        >
          {/* Signal Overlay serves as the Top Toolbar */}
          <SignalOverlay />
          <div className="flex-1 relative w-full h-full overflow-hidden">
            <TradingViewWidget />
          </div>
        </div>

        <Routes>
          <Route element={<GuestLayout />}>
            <Route path="/" element={<Landing />} />
            <Route path="/login" element={<Login />} />
            <Route path="/signup" element={<SignUp />} />
            <Route path="/forgot-password" element={<ForgotPassword />} />
          </Route>

          <Route element={<ProtectedRoute><AppLayout /></ProtectedRoute>}>
            <Route path="/dashboard" element={<Trader />} />
            <Route path="/analysis" element={<Analysis />} />
            <Route path="/market-news" element={<MarketNews />} />
            <Route path="/predictor" element={<Predictor />} />
            <Route path="/journal" element={<Journal />} />
            <Route path="/history" element={<History />} />
            <Route path="/apex-ai" element={<ApexAI />} />
            <Route path="/coders" element={<CodersPage />} />
          </Route>

          <Route element={<ProtectedRoute><ChartingLayout /></ProtectedRoute>}>
            <Route path="/charting" element={<Charting />} />
          </Route>

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>

        {/* Hide AI Agent when on the charting page */}
        {!isChartingPage && <AIAgent />}

        {environment === 'aistudio' && <ErrorLog />}
      </div>
    </ResponsiveFix>
  );
};

const GuestLayout: React.FC = () => {
  const { user } = useAuth();
  if (!user.isGuest) {
    return <Navigate to="/dashboard" />;
  }
  return (
    <>
      <Header />
      <div className="flex-grow overflow-y-auto flex flex-col">
        <main className="flex-grow w-full flex flex-col py-4 sm:py-6 lg:py-8">
            <div className="w-full max-w-7xl mx-auto px-4 sm:px-6 lg:py-8 flex-1 flex flex-col justify-center">
            <Outlet />
            </div>
        </main>
        <Footer />
      </div>
    </>
  );
};

const AppLayout: React.FC = () => {
  const location = useLocation();
  const isDashboard = location.pathname === '/dashboard';

  return (
    <>
      <Header />
      {/* Navigation bar ONLY visible on dashboard */}
      {isDashboard && <TabbedNav />}
      <div className="flex-grow overflow-y-auto flex flex-col relative z-10">
          <main className={`flex-grow w-full flex flex-col ${isDashboard ? 'py-4 sm:py-6' : 'py-0'} lg:py-8`}>
              <div className={`w-full max-w-7xl mx-auto ${isDashboard ? 'px-4 sm:px-6' : 'px-2'} lg:py-8 flex-1 flex flex-col justify-center`}>
                  <Outlet />
              </div>
          </main>
          <Footer />
      </div>
    </>
  );
};

const ChartingLayout: React.FC = () => (
  <>
    <Header />
    <main className="flex-grow w-full relative overflow-hidden pointer-events-none">
        <Outlet />
    </main>
  </>
);

const ProtectedRoute: React.FC<{ children: React.ReactElement }> = ({ children }) => {
  const { user } = useAuth();
  return user.isGuest ? <Navigate to="/login" /> : children;
};

const CodersPage: React.FC = () => (
    <div className="space-y-16">
        <section id="coders"><Introduction /></section>
        <section id="bot-maker"><BotMaker /></section>
        <section id="indicator-maker"><IndicatorMaker /></section>
    </div>
);


export default App;

import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import ThemeToggle from './ThemeToggle';
import Logo from './Logo';

const Header: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  const isDashboard = location.pathname === '/dashboard';
  const isLanding = location.pathname === '/';
  const isCharting = location.pathname === '/charting';

  // Show back button if user is NOT on the primary dashboard/landing and history exists
  // Removing user.uid dependency for the back button to ensure it works for everyone
  const showBack = !isLanding && !isDashboard;

  const navLinkClassName = "px-3 py-2 rounded-md text-sm font-medium transition-colors text-gray-600 dark:text-gray-300 hover:bg-black/10 dark:hover:bg-white/10";

  const guestLinks = (isMobile = false) => {
    const mobileClass = isMobile ? 'block' : '';
    return (
        <>
            <a href="#features" onClick={() => setIsOpen(false)} className={`${navLinkClassName} ${mobileClass}`}>Features</a>
            <Link to="/login" onClick={() => setIsOpen(false)} className={`${navLinkClassName} ${mobileClass}`}>Login</Link>
            <Link to="/signup" onClick={() => setIsOpen(false)} className={`${navLinkClassName} ${mobileClass}`}>Sign Up</Link>
        </>
    );
  };

  const handleBack = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Use navigate -1 to go back in router history
    navigate(-1);
  };

  return (
    <header className={`bg-white/50 dark:bg-gray-900/50 backdrop-blur-lg shadow-md sticky top-0 z-50 border-b border-white/20 dark:border-white/10 transition-all duration-300 ${isCharting ? 'h-10' : 'h-16'}`}>
      <div className="w-full max-w-full mx-auto px-4 sm:px-6 lg:px-8 h-full">
        <div className="flex items-center justify-between h-full">
          <div className="flex-shrink-0 flex items-center gap-4">
            {showBack ? (
                <button 
                  onClick={handleBack}
                  type="button"
                  className="flex items-center gap-2 text-gray-600 dark:text-gray-300 hover:text-red-500 dark:hover:text-red-400 transition-colors px-3 py-1.5 rounded-lg bg-gray-500/5 hover:bg-gray-500/10 border border-transparent hover:border-gray-500/20 active:scale-95"
                >
                    <i className="fas fa-chevron-left text-xs"></i>
                    <span className="font-bold text-xs">Back</span>
                </button>
            ) : (
                <Logo />
            )}
          </div>
          <div className="hidden md:block">
            <div className="ml-10 flex items-center space-x-4">
              {isCharting ? (
                  <div className="scale-90 origin-right">
                    <ThemeToggle />
                  </div>
              ) : user.isGuest ? (
                guestLinks()
              ) : (
                <>
                    <ThemeToggle />
                    <button onClick={logout} className={navLinkClassName}>Logout</button>
                </>
              )}
            </div>
          </div>
          <div className="-mr-2 flex md:hidden items-center">
            {isCharting ? (
                 <div className="scale-75 origin-right">
                    <ThemeToggle />
                 </div>
            ) : (
                <>
                    <ThemeToggle />
                    {user.isGuest ? (
                    <button
                        onClick={() => setIsOpen(!isOpen)}
                        type="button"
                        className="ml-2 bg-gray-500/10 inline-flex items-center justify-center p-2 rounded-md text-gray-500 dark:text-gray-400 hover:text-gray-800 dark:hover:text-white hover:bg-black/10 dark:hover:bg-white/10 focus:outline-none"
                    >
                        <span className="sr-only">Open main menu</span>
                        <svg className={`${isOpen ? 'hidden' : 'block'} h-6 w-6`} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
                        </svg>
                        <svg className={`${isOpen ? 'block' : 'hidden'} h-6 w-6`} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                        </svg>
                    </button>
                    ) : (
                    <button onClick={logout} className={`${navLinkClassName} ml-2`}>Logout</button>
                    )}
                </>
            )}
          </div>
        </div>
      </div>
      {isOpen && user.isGuest && !isCharting && (
        <div className="md:hidden">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
              {guestLinks(true)}
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

