                    <span className="text-xs font-black bg-gray-500/10 dark:bg-white/10 px-3 py-1.5 rounded-full text-gray-700 dark:text-gray-300 flex-shrink-0 border border-white/10 shadow-sm uppercase tracking-widest">{time}</span>
                </div>

                <p className="text-sm text-gray-600 dark:text-gray-400 mb-4 font-medium leading-relaxed">{potential_effect}</p>

                <div className="flex items-center gap-2 flex-wrap mb-4">
