const DailyBiasCard: React.FC<{ biases?: DailyBias[], isSeasonal: boolean }> = ({ biases, isSeasonal }) => {
    const [currentIndex, setCurrentIndex] = useState(0);
    const [fade, setFade] = useState(false);

    const safeBiases = Array.isArray(biases) ? biases : [];

    useEffect(() => {
        if (safeBiases.length === 0) return;
        const interval = setInterval(() => {
            triggerTransition();
        }, 60000); // 1 minute
        return () => clearInterval(interval);
    }, [safeBiases.length]);

    const triggerTransition = (nextIndex?: number) => {
        if (safeBiases.length === 0) return;
        setFade(true);
        setTimeout(() => {
            setCurrentIndex(prev => nextIndex !== undefined ? nextIndex : (prev + 1) % safeBiases.length);
            setFade(false);
        }, 300); // Wait for fade out
    };

    const handleClick = () => {
        triggerTransition();
    };

    if (safeBiases.length === 0) return (
        <div className="bg-black/20 backdrop-blur-xl border border-white/10 rounded-[2.5rem] p-8 text-white h-full flex items-center justify-center">
            <p className="font-black uppercase tracking-widest opacity-30">Neural Sync Required</p>
        </div>
    );


    const currentBias = safeBiases[currentIndex] || safeBiases[0];
    const isBullish = currentBias.bias === 'Bullish';
    const isBearish = currentBias.bias === 'Bearish';

    // Dynamic styles based on bias
    const gradientClass = isBullish 
        ? "from-green-600/90 to-emerald-800/90" 
        : isBearish 
            ? "from-red-600/90 to-rose-800/90" 
            : "from-blue-600/90 to-indigo-800/90";

    const strengthBadgeClass = isBullish 
        ? "bg-green-400/20 text-green-100 border-green-400/30" 
        : isBearish 
            ? "bg-red-400/20 text-red-100 border-red-400/30" 
            : "bg-blue-400/20 text-blue-100 border-blue-400/30";

    return (
        <div 
            onClick={handleClick}
            className={`relative cursor-pointer bg-gradient-to-br ${gradientClass} backdrop-blur-2xl border border-white/30 rounded-[2.5rem] p-8 text-white shadow-2xl h-full flex flex-col justify-between transition-all duration-500 hover:scale-[1.02] ${isSeasonal ? 'seasonal-glow' : ''}`}
        >
            {isSeasonal && <div className="seasonal-badge">🟢 Seasonal Bias Active</div>}
            <div className={`transition-opacity duration-300 ${fade ? 'opacity-0' : 'opacity-100'}`}>
                <div className="flex justify-between items-start mb-6">
                    <h3 className="font-black text-xl mb-1 flex items-center gap-3 uppercase tracking-tighter">
                        <i className="fas fa-microchip opacity-80 text-sm"></i> Neural Bias
                    </h3>
                    <div className="flex gap-1.5 p-1.5 bg-black/20 rounded-full">
                        {safeBiases.map((_, i) => (
                            <div key={i} className={`h-1.5 w-1.5 rounded-full transition-all ${i === currentIndex ? 'bg-white w-4' : 'bg-white/20'}`}></div>
                        ))}
                    </div>
                </div>

                <p className="text-white text-base font-bold leading-relaxed min-h-[4rem] drop-shadow-md">
                    {currentBias.reasoning}
                </p>

                <div className="mt-8 pt-8 border-t border-white/20 flex justify-between items-end">
                    <div>
                        <p className="text-[10px] text-white/60 uppercase font-black tracking-[0.2em] mb-1">Target Instrument</p>
                        <p className="font-black text-3xl tracking-tighter">{currentBias.pair}</p>
                    </div>
                    <div className="text-right">
                         <span className={`${strengthBadgeClass} px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest border backdrop-blur-xl shadow-lg`}>
                            {currentBias.strength} {currentBias.bias}
                        </span>
                    </div>
                </div>
            </div>
             <p className="text-[9px] text-white/40 text-center mt-6 font-black uppercase tracking-widest">Oracle Stream Active • 60s Cycle</p>
        </div>
    );
};

