// Helper to safely render text that might accidentally be an object from the AI response
// This fixes "Uncaught Error: Minified React error #31"
const safeText = (val: any): string => {
    if (val === null || val === undefined) return '';
    if (typeof val === 'string') return val;
    if (typeof val === 'number') return String(val);
    try {
        // If it's an object with keys (like {VIX}), flatten it or stringify it
        if (typeof val === 'object') {
            const keys = Object.keys(val);
            if (keys.length === 1) return String(val[keys[0]]);
            return JSON.stringify(val);
        }
        return String(val);
    } catch (e) {
        return 'Data Error';
    }
};

const Sparkline: React.FC<{ data: number[], color: string }> = ({ data, color }) => {
    const height = 40;
    const width = 100;
    if (!Array.isArray(data) || data.length < 2) return null;

    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;

    const points = data.map((d, i) => {
        const x = (i / (data.length - 1)) * width;
        const y = height - ((d - min) / range) * height;
        return `${x},${y}`;
    }).join(' ');

    return (
        <svg width="100%" height={height} viewBox={`0 0 ${width} ${height}`} className="overflow-visible">
            <polyline
                fill="none"
                stroke={color}
                strokeWidth="2"
                points={points}
                vectorEffect="non-scaling-stroke"
            />
        </svg>
    );
};

const ConfidenceMeter: React.FC<{ value: number }> = ({ value }) => {
    // Value 0-100
    let color = 'bg-red-500';
    if (value > 75) color = 'bg-green-500';
    else if (value > 45) color = 'bg-yellow-500';

    return (
        <div className="w-full h-2 bg-black/10 dark:bg-white/10 rounded-full overflow-hidden mt-1 shadow-inner">
            <div 
                className={`h-full ${color} transition-all duration-500 shadow-[0_0_10px_rgba(0,0,0,0.2)]`} 
                style={{ width: `${value}%` }}
            ></div>
        </div>
    );
};

const Card: React.FC<{ title: string; children: React.ReactNode; className?: string; icon?: string, isSeasonalGlow?: boolean; }> = ({ title, children, className = "", icon, isSeasonalGlow }) => (
